import React from 'react';
import {
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  PieChart, Pie, Cell
} from 'recharts';
import { transactions, monthlySpending, accounts, anomalies, categoryColors } from '../data/mockData';
import { useNavigate } from 'react-router-dom';

const formatCurrency = (value) =>
  new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(value);

function CustomTooltip({ active, payload, label }) {
  if (!active || !payload?.length) return null;
  return (
    <div className="custom-tooltip">
      <div className="label">{label}</div>
      {payload.map((p, i) => (
        <div key={i} className="value" style={{ color: p.color }}>
          {p.name}: {formatCurrency(p.value)}
        </div>
      ))}
    </div>
  );
}

export default function Dashboard() {
  const navigate = useNavigate();

  const totalBalance = accounts.reduce((s, a) => s + a.balance, 0);
  const thisMonthTxns = transactions.filter(t => t.date.startsWith('2026-03'));
  const thisMonthSpending = thisMonthTxns.filter(t => t.amount < 0).reduce((s, t) => s + Math.abs(t.amount), 0);
  const thisMonthIncome = thisMonthTxns.filter(t => t.amount > 0).reduce((s, t) => s + t.amount, 0);

  // Category breakdown for pie chart
  const categoryTotals = {};
  thisMonthTxns.filter(t => t.amount < 0).forEach(t => {
    categoryTotals[t.category] = (categoryTotals[t.category] || 0) + Math.abs(t.amount);
  });
  const pieData = Object.entries(categoryTotals)
    .map(([name, value]) => ({ name, value: Math.round(value * 100) / 100 }))
    .sort((a, b) => b.value - a.value);

  const recentTransactions = transactions.slice(0, 8);

  return (
    <div>
      <div className="page-header">
        <h1>Dashboard</h1>
        <p>Your financial overview for March 2026</p>
      </div>

      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-label">Total Balance</div>
          <div className="stat-value">{formatCurrency(totalBalance)}</div>
          <div className="stat-change positive">+2.4% from last month</div>
        </div>
        <div className="stat-card">
          <div className="stat-label">Monthly Spending</div>
          <div className="stat-value">{formatCurrency(thisMonthSpending)}</div>
          <div className="stat-change negative">+8.1% from last month</div>
        </div>
        <div className="stat-card">
          <div className="stat-label">Monthly Income</div>
          <div className="stat-value">{formatCurrency(thisMonthIncome)}</div>
          <div className="stat-change positive">Same as last month</div>
        </div>
        <div className="stat-card" style={{ cursor: 'pointer' }} onClick={() => navigate('/alerts')}>
          <div className="stat-label">Anomalies Detected</div>
          <div className="stat-value" style={{ color: 'var(--red)' }}>{anomalies.length}</div>
          <div className="stat-change negative">Requires attention</div>
        </div>
      </div>

      <div className="charts-row">
        <div className="card">
          <div className="card-header">
            <h3>Spending Trend</h3>
          </div>
          <ResponsiveContainer width="100%" height={280}>
            <AreaChart data={monthlySpending}>
              <defs>
                <linearGradient id="spendGrad" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="0%" stopColor="#6366f1" stopOpacity={0.3} />
                  <stop offset="100%" stopColor="#6366f1" stopOpacity={0} />
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="month" tick={{ fontSize: 12 }} />
              <YAxis tick={{ fontSize: 12 }} tickFormatter={v => `$${v}`} />
              <Tooltip content={<CustomTooltip />} />
              <Area type="monotone" dataKey="total" stroke="#6366f1" fill="url(#spendGrad)" strokeWidth={2} />
            </AreaChart>
          </ResponsiveContainer>
        </div>

        <div className="card">
          <div className="card-header">
            <h3>Spending by Category</h3>
          </div>
          <ResponsiveContainer width="100%" height={280}>
            <PieChart>
              <Pie
                data={pieData}
                cx="50%"
                cy="50%"
                innerRadius={60}
                outerRadius={100}
                paddingAngle={3}
                dataKey="value"
              >
                {pieData.map((entry, i) => (
                  <Cell key={i} fill={categoryColors[entry.name] || '#6b7280'} />
                ))}
              </Pie>
              <Tooltip
                formatter={(value) => formatCurrency(value)}
                contentStyle={{ background: '#1a1d27', border: '1px solid #2a2d3e', borderRadius: 8 }}
              />
            </PieChart>
          </ResponsiveContainer>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px 16px', marginTop: 8 }}>
            {pieData.slice(0, 6).map(d => (
              <div key={d.name} style={{ display: 'flex', alignItems: 'center', gap: 6, fontSize: 12 }}>
                <div style={{ width: 8, height: 8, borderRadius: 2, background: categoryColors[d.name] }} />
                <span style={{ color: 'var(--text-secondary)' }}>{d.name}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="card recent-section">
        <div className="card-header">
          <h3>Recent Transactions</h3>
          <button className="btn btn-ghost" onClick={() => navigate('/transactions')}>View All</button>
        </div>
        <div className="table-wrapper">
          <table>
            <thead>
              <tr>
                <th>Date</th>
                <th>Merchant</th>
                <th>Category</th>
                <th>Amount</th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              {recentTransactions.map(t => (
                <tr key={t.id}>
                  <td style={{ color: 'var(--text-secondary)' }}>{t.date}</td>
                  <td>
                    {t.merchant}
                    {t.anomaly && <span style={{ color: 'var(--red)', marginLeft: 8, fontSize: 12 }}>FLAGGED</span>}
                  </td>
                  <td><span className="category-tag">{t.category}</span></td>
                  <td className={t.amount >= 0 ? 'amount-positive' : 'amount-negative'}>
                    {t.amount >= 0 ? '+' : ''}{formatCurrency(t.amount)}
                  </td>
                  <td>{t.pending ? <span className="pending-tag">Pending</span> : <span style={{ color: 'var(--text-muted)', fontSize: 13 }}>Cleared</span>}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
